import{_ as t,o,c as r,ak as a}from"./chunks/framework.oFDsBAuP.js";const g=JSON.parse('{"title":"重排序文档","description":"POST /v1/rerank — 按查询相关性对文档重排序","frontmatter":{"title":"重排序文档","description":"POST /v1/rerank — 按查询相关性对文档重排序","apiMethod":"POST","apiPath":"/v1/rerank","outline":false},"headers":[],"relativePath":"api/ai-model/rerank/creatererank.md","filePath":"api/ai-model/rerank/creatererank.md"}'),d={name:"api/ai-model/rerank/creatererank.md"};function n(c,e,i,l,s,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="重排序文档" tabindex="-1">重排序文档 <a class="header-anchor" href="#重排序文档" aria-label="Permalink to &quot;重排序文档&quot;">​</a></h1><blockquote><p>根据与查询的相关性对文档进行重排序。</p></blockquote><p>使用语义相似度模型对候选文档重排序，适用于搜索排序、RAG 等场景。</p><p>本端点同样可能耗时较长，建议 HTTP 超时 <strong>不低于 120s</strong>。</p><table tabindex="0"><thead><tr><th>项目</th><th>值</th></tr></thead><tbody><tr><td>方法</td><td><code>POST</code></td></tr><tr><td>路径</td><td><code>/v1/rerank</code></td></tr><tr><td>认证</td><td><code>Authorization: Bearer &lt;token&gt;</code></td></tr></tbody></table><p>示例网关：<code>https://minitoken.vip/v1</code>。</p><h2 id="请求体" tabindex="-1">请求体 <a class="header-anchor" href="#请求体" aria-label="Permalink to &quot;请求体&quot;">​</a></h2><ul><li><strong><code>model</code></strong>：重排序模型 ID（如 <code>BAAI/bge-reranker-v2-m3</code>、<code>qwen3-rerank</code> 等，以网关为准）。</li><li><strong><code>query</code></strong>：查询语句。</li><li><strong><code>documents</code></strong>：待排序文档字符串数组。</li><li><strong><code>top_n</code></strong>：返回前若干条；默认可视为全部。</li><li><strong><code>return_documents</code></strong>：是否在结果中包含原始文档文本。</li></ul><h2 id="响应" tabindex="-1">响应 <a class="header-anchor" href="#响应" aria-label="Permalink to &quot;响应&quot;">​</a></h2><ul><li><strong><code>results</code></strong>：已排序结果列表；每项常含： <ul><li><strong><code>index</code></strong>：原始文档下标</li><li><strong><code>relevance_score</code></strong>：相关性分数（如 0–1）</li><li><strong><code>document</code></strong>：原文（当 <code>return_documents=true</code>）</li></ul></li><li><strong><code>model</code></strong>、<strong><code>usage</code></strong>（token 统计）。</li></ul><h2 id="另见" tabindex="-1">另见 <a class="header-anchor" href="#另见" aria-label="Permalink to &quot;另见&quot;">​</a></h2><ul><li><a href="./../embeddings/createembedding.html">创建 Embedding</a> — <code>POST /v1/embeddings</code></li></ul>',12)])])}const m=t(d,[["render",n]]);export{g as __pageData,m as default};
